1: // Package debuglog provides best-effort, privacy-conscious persistent diagnostics.
2: // Logging must never crash or block the main application path.
3: package debuglog
4: 
5: import (
6: 	"bufio"
7: 	"encoding/json"
8: 	"errors"
9: 	"fmt"
10: 	"os"
11: 	"path/filepath"
12: 	"regexp"
13: 	"sort"
14: 	"strings"
15: 	"sync"
16: 	"sync/atomic"
17: 	"time"
18: )
19: 
20: const (
21: 	fileName     = "debug.log"
22: 	maxLogBytes  = 5 << 20
23: 	rotatedFiles = 3
24: )
25: 
26: var (
27: 	mu sync.Mutex
28: 	// activePath is set when the configured directory is unavailable and the
29: 	// logger successfully falls back to the system temporary directory.
30: 	activePath atomic.Value
31: 
32: 	bearerPattern = regexp.MustCompile(`(?i)(authorization\s*[:=]\s*bearer\s+)[^\s"']+`)
33: 	keyPattern    = regexp.MustCompile(`(?i)((?:api[_-]?key|token|secret|password)\s*[:=]\s*)[^\s,"']+`)
34: 	openAIKey     = regexp.MustCompile(`\bsk-[A-Za-z0-9_-]{12,}\b`)
35: )
