37: // Entry is one JSON-lines diagnostic record.
38: type Entry struct {
39: 	Time      time.Time      `json:"time"`
40: 	Level     string         `json:"level"`
41: 	Component string         `json:"component"`
42: 	Event     string         `json:"event"`
43: 	Message   string         `json:"message"`
44: 	Fields    map[string]any `json:"fields,omitempty"`
45: }
46: 
47: // Path returns the active diagnostic log path. EPHEMERA_DEBUG_LOG can override
48: // the default for portable installations and tests.
49: func Path() string {
50: 	if explicit := strings.TrimSpace(os.Getenv("EPHEMERA_DEBUG_LOG")); explicit != "" {
51: 		return filepath.Clean(explicit)
52: 	}
53: 	if active, ok := activePath.Load().(string); ok && strings.TrimSpace(active) != "" {
54: 		return active
55: 	}
56: 	return configuredPath()
57: }
58: 
59: func configuredPath() string {
60: 	if root, err := os.UserConfigDir(); err == nil && strings.TrimSpace(root) != "" {
61: 		return filepath.Join(root, "ephemera", "logs", fileName)
62: 	}
63: 	if root, err := os.UserCacheDir(); err == nil && strings.TrimSpace(root) != "" {
64: 		return filepath.Join(root, "ephemera", "logs", fileName)
65: 	}
66: 	return filepath.Join(os.TempDir(), "ephemera", fileName)
67: }
68: 
69: // Error records an encountered error. It intentionally returns no error so the
70: // diagnostic path cannot mask the original failure.
71: func Error(component, event string, err error, fields map[string]any) {
72: 	if err == nil {
73: 		return
74: 	}
75: 	_ = Write("error", component, event, err.Error(), fields)
76: }
77: 
78: // Failure records a non-error failure state such as a failed verification or
79: // an unexpectedly closed stream.
80: func Failure(component, event, message string, fields map[string]any) {
81: 	_ = Write("error", component, event, message, fields)
82: }
83: 
84: // Warning records a recoverable failure, retry, or degraded fallback.
85: func Warning(component, event, message string, fields map[string]any) {
86: 	_ = Write("warning", component, event, message, fields)
87: }
