89: // Write appends one redacted JSON-lines entry and rotates bounded log files.
90: func Write(level, component, event, message string, fields map[string]any) error {
91: 	entry := Entry{
92: 		Time:      time.Now().UTC(),
93: 		Level:     fallback(strings.ToLower(strings.TrimSpace(level)), "error"),
94: 		Component: fallback(strings.TrimSpace(component), "ephemera"),
95: 		Event:     fallback(strings.TrimSpace(event), "failure"),
96: 		Message:   redact(strings.TrimSpace(message)),
97: 		Fields:    sanitizeMap(fields, 0),
98: 	}
99: 	data, err := json.Marshal(entry)
100: 	if err != nil {
101: 		return err
102: 	}
103: 	data = append(data, '\n')
104: 
105: 	mu.Lock()
106: 	defer mu.Unlock()
107: 
108: 	path := configuredPath()
109: 	if explicit := strings.TrimSpace(os.Getenv("EPHEMERA_DEBUG_LOG")); explicit != "" {
110: 		path = filepath.Clean(explicit)
111: 	}
112: 	if err := writeAt(path, data); err == nil {
113: 		activePath.Store(path)
114: 		mirrorSessionEntry(entry, data)
115: 		return nil
116: 	} else {
117: 		primaryErr := err
118: 		fallback := filepath.Join(os.TempDir(), "ephemera", fileName)
119: 		if filepath.Clean(fallback) == filepath.Clean(path) {
120: 			return primaryErr
121: 		}
122: 		if fallbackErr := writeAt(fallback, data); fallbackErr != nil {
123: 			return fmt.Errorf("write debug log: %v; fallback: %w", primaryErr, fallbackErr)
124: 		}
125: 		activePath.Store(fallback)
126: 		mirrorSessionEntry(entry, data)
127: 		return nil
128: 	}
129: }
