203: func rotateIfNeeded(path string, incoming int64) error {
204: 	info, err := os.Stat(path)
205: 	if errors.Is(err, os.ErrNotExist) {
206: 		return nil
207: 	}
208: 	if err != nil {
209: 		return err
210: 	}
211: 	if info.Size()+incoming <= maxLogBytes {
212: 		return nil
213: 	}
214: 	_ = os.Remove(fmt.Sprintf("%s.%d", path, rotatedFiles))
215: 	for index := rotatedFiles - 1; index >= 1; index-- {
216: 		oldPath := fmt.Sprintf("%s.%d", path, index)
217: 		newPath := fmt.Sprintf("%s.%d", path, index+1)
218: 		if err := os.Rename(oldPath, newPath); err != nil && !errors.Is(err, os.ErrNotExist) {
219: 			return err
220: 		}
221: 	}
222: 	return os.Rename(path, path+".1")
223: }
