225: func sanitizeFields(fields map[string]any) map[string]any {
226: 	return sanitizeMap(fields, 0)
227: }
228: 
229: func sanitizeMap(fields map[string]any, depth int) map[string]any {
230: 	if len(fields) == 0 {
231: 		return nil
232: 	}
233: 	if depth > 4 {
234: 		return map[string]any{"value": "[TRUNCATED]"}
235: 	}
236: 	out := make(map[string]any, len(fields))
237: 	keys := make([]string, 0, len(fields))
238: 	for key := range fields {
239: 		keys = append(keys, key)
240: 	}
241: 	sort.Strings(keys)
242: 	for _, key := range keys {
243: 		if sensitiveKey(key) {
244: 			out[key] = "[REDACTED]"
245: 			continue
246: 		}
247: 		out[key] = sanitizeValue(fields[key], depth+1)
248: 	}
249: 	return out
250: }
251: 
252: func sanitizeValue(value any, depth int) any {
253: 	if depth > 4 {
254: 		return "[TRUNCATED]"
255: 	}
256: 	switch typed := value.(type) {
257: 	case string:
258: 		return redact(limitString(typed, 4000))
259: 	case error:
260: 		return redact(limitString(typed.Error(), 4000))
261: 	case map[string]any:
262: 		return sanitizeMap(typed, depth+1)
263: 	case []string:
264: 		out := make([]string, 0, min(len(typed), 32))
265: 		for _, item := range typed {
266: 			if len(out) == cap(out) {
267: 				break
268: 			}
269: 			out = append(out, redact(limitString(item, 1000)))
270: 		}
271: 		return out
272: 	case []any:
273: 		limit := min(len(typed), 32)
274: 		out := make([]any, 0, limit)
275: 		for _, item := range typed[:limit] {
276: 			out = append(out, sanitizeValue(item, depth+1))
277: 		}
278: 		return out
279: 	default:
280: 		if _, err := json.Marshal(value); err == nil {
281: 			return value
282: 		}
283: 		return redact(limitString(fmt.Sprint(value), 1000))
284: 	}
285: }
286: 
287: func sensitiveKey(key string) bool {
288: 	key = strings.ToLower(strings.TrimSpace(key))
289: 	for _, marker := range []string{"key", "secret", "password", "authorization", "credential"} {
290: 		if strings.Contains(key, marker) {
291: 			return true
292: 		}
293: 	}
294: 	// Token counts and budgets are diagnostics, not credentials. Only redact
295: 	// fields whose name identifies an actual bearer/access token.
296: 	if strings.Contains(key, "tokens") || strings.Contains(key, "token_count") || strings.Contains(key, "token_budget") {
297: 		return false
298: 	}
299: 	switch key {
300: 	case "token", "access_token", "refresh_token", "auth_token", "bearer_token", "api_token", "id_token":
301: 		return true
302: 	}
303: 	return strings.HasSuffix(key, "_access_token") || strings.HasSuffix(key, "_refresh_token")
304: }
305: 
306: func redact(value string) string {
307: 	value = bearerPattern.ReplaceAllString(value, `${1}[REDACTED]`)
308: 	value = keyPattern.ReplaceAllString(value, `${1}[REDACTED]`)
309: 	return openAIKey.ReplaceAllString(value, "[REDACTED]")
310: }
311: 
312: func limitString(value string, max int) string {
313: 	runes := []rune(value)
314: 	if len(runes) <= max {
315: 		return value
316: 	}
317: 	return string(runes[:max]) + "…"
318: }
319: 
320: func fallback(value, defaultValue string) string {
321: 	if value == "" {
322: 		return defaultValue
323: 	}
324: 	return value
325: }
