119: 		if filepath.Clean(fallback) == filepath.Clean(path) {
120: 			return primaryErr
121: 		}
122: 		if fallbackErr := writeAt(fallback, data); fallbackErr != nil {
123: 			return fmt.Errorf("write debug log: %v; fallback: %w", primaryErr, fallbackErr)
124: 		}
125: 		activePath.Store(fallback)
126: 		mirrorSessionEntry(entry, data)
127: 		return nil
128: 	}
129: }
