131: func writeAt(path string, data []byte) error {
132: 	if err := os.MkdirAll(filepath.Dir(path), 0o700); err != nil {
133: 		return err
134: 	}
135: 	if err := rotateIfNeeded(path, int64(len(data))); err != nil {
136: 		return err
137: 	}
138: 	file, err := os.OpenFile(path, os.O_CREATE|os.O_WRONLY|os.O_APPEND, 0o600)
139: 	if err != nil {
140: 		return err
141: 	}
142: 	defer file.Close()
143: 	_ = file.Chmod(0o600)
144: 	if _, err := file.Write(data); err != nil {
145: 		return err
146: 	}
147: 	return file.Sync()
148: }
