150: // Recent returns the newest entries in chronological order.
151: func Recent(limit int) ([]Entry, error) {
152: 	if limit < 1 {
153: 		limit = 20
154: 	}
155: 	mu.Lock()
156: 	defer mu.Unlock()
157: 
158: 	file, err := os.Open(Path())
159: 	if errors.Is(err, os.ErrNotExist) {
160: 		return nil, nil
161: 	}
162: 	if err != nil {
163: 		return nil, err
164: 	}
165: 	defer file.Close()
166: 
167: 	entries := make([]Entry, 0, limit)
168: 	scanner := bufio.NewScanner(file)
169: 	scanner.Buffer(make([]byte, 64<<10), 2<<20)
170: 	for scanner.Scan() {
171: 		var entry Entry
172: 		if json.Unmarshal(scanner.Bytes(), &entry) != nil {
173: 			continue
174: 		}
175: 		if len(entries) == limit {
176: 			copy(entries, entries[1:])
177: 			entries[len(entries)-1] = entry
178: 		} else {
179: 			entries = append(entries, entry)
180: 		}
181: 	}
182: 	return entries, scanner.Err()
183: }
