185: // Clear removes the active and rotated diagnostic logs.
186: func Clear() error {
187: 	mu.Lock()
188: 	defer mu.Unlock()
189: 	path := Path()
190: 	var first error
191: 	for index := 0; index <= rotatedFiles; index++ {
192: 		candidate := path
193: 		if index > 0 {
194: 			candidate = fmt.Sprintf("%s.%d", path, index)
195: 		}
196: 		if err := os.Remove(candidate); err != nil && !errors.Is(err, os.ErrNotExist) && first == nil {
197: 			first = err
198: 		}
199: 	}
200: 	return first
201: }
