229: func sanitizeMap(fields map[string]any, depth int) map[string]any {
230: 	if len(fields) == 0 {
231: 		return nil
232: 	}
233: 	if depth > 4 {
234: 		return map[string]any{"value": "[TRUNCATED]"}
235: 	}
236: 	out := make(map[string]any, len(fields))
237: 	keys := make([]string, 0, len(fields))
238: 	for key := range fields {
239: 		keys = append(keys, key)
240: 	}
241: 	sort.Strings(keys)
242: 	for _, key := range keys {
243: 		if sensitiveKey(key) {
244: 			out[key] = "[REDACTED]"
245: 			continue
246: 		}
247: 		out[key] = sanitizeValue(fields[key], depth+1)
248: 	}
249: 	return out
250: }
251: 
252: func sanitizeValue(value any, depth int) any {
253: 	if depth > 4 {
254: 		return "[TRUNCATED]"
255: 	}
256: 	switch typed := value.(type) {
257: 	case string:
258: 		return redact(limitString(typed, 4000))
259: 	case error:
260: 		return redact(limitString(typed.Error(), 4000))
261: 	case map[string]any:
262: 		return sanitizeMap(typed, depth+1)
263: 	case []string:
264: 		out := make([]string, 0, min(len(typed), 32))
265: 		for _, item := range typed {
266: 			if len(out) == cap(out) {
267: 				break
268: 			}
269: 			out = append(out, redact(limitString(item, 1000)))
270: 		}
271: 		return out
272: 	case []any:
273: 		limit := min(len(typed), 32)
274: 		out := make([]any, 0, limit)
275: 		for _, item := range typed[:limit] {
276: 			out = append(out, sanitizeValue(item, depth+1))
277: 		}
278: 		return out
279: 	default:
280: 		if _, err := json.Marshal(value); err == nil {
281: 			return value
282: 		}
283: 		return redact(limitString(fmt.Sprint(value), 1000))
284: 	}
285: }
