306: func redact(value string) string {
307: 	value = bearerPattern.ReplaceAllString(value, `${1}[REDACTED]`)
308: 	value = keyPattern.ReplaceAllString(value, `${1}[REDACTED]`)
309: 	return openAIKey.ReplaceAllString(value, "[REDACTED]")
310: }
